<template><div class="page-container"><FilterBar @search="onSearch" @reset="onReset"><a-input v-model:value="f.orderNo" placeholder="订单号" allow-clear style="width:200px"/><a-select v-model:value="f.payStatus" placeholder="状态" allow-clear style="width:120px"><a-select-option value="paid">已支付</a-select-option><a-select-option value="refunding">退款中</a-select-option><a-select-option value="refunded">已退款</a-select-option></a-select><a-range-picker v-model:value="f.dateRange" style="width:240px"/></FilterBar><div class="page-card"><DataTable :columns="cols" :data-source="list" :loading="ld" :total="t" v-model:page="p" v-model:page-size="ps"><template #amount="{r}">{{(r.amount/100).toFixed(2)}}</template><template #payStatus="{r}"><StatusTag :status="r.payStatus" type="payment"/></template></DataTable></div></div></template>
<script setup lang="ts">import {ref,reactive} from 'vue';import {financeApi} from '@/api/finance';import FilterBar from '@/components/common/FilterBar.vue';import DataTable from '@/components/common/DataTable.vue';import StatusTag from '@/components/common/StatusTag.vue'
const ld=ref(false),list=ref<any[]>([]),t=ref(0),p=ref(1),ps=ref(20);const f=reactive({orderNo:'',payStatus:undefined as string|undefined,dateRange:undefined as any})
const cols=[{title:'订单号',dataIndex:'orderNo',width:180},{title:'用户',dataIndex:'userNickname',width:100},{title:'业务类型',dataIndex:'bizType',width:90},{title:'金额',dataIndex:'amount',width:100,slot:'amount'},{title:'支付方式',dataIndex:'payMethod',width:90},{title:'状态',dataIndex:'payStatus',width:80,slot:'payStatus'},{title:'支付时间',dataIndex:'payTime',width:160},{title:'创建时间',dataIndex:'createdAt',width:160}]
async function ft(){ld.value=true;try{const r=await financeApi.getPaymentList({page:p.value,pageSize:ps.value,...f});list.value=r.data.data?.list||r.data?.list||[];t.value=r.data.data?.total||r.data?.total||0}catch{}finally{ld.value=false}}
function onSearch(){p.value=1;ft()};function onReset(){f.orderNo='';f.payStatus=undefined;f.dateRange=undefined;onSearch()}
ft();
</script>
